+fn validate_thread_cpuclockid(clockid: libc::clockid_t) -> Result<(), c_int> {
+    let mut ts: libc::timespec = unsafe { std::mem::zeroed() };
+    match unsafe {
+        raw_syscall::sys_clock_getres(clockid, &mut ts as *mut libc::timespec as *mut u8)
